// // This module performs a 3x3 Gaussian blur filter on a grayscale image.
// Input: 9 8-bit pixels
// Output: A single 8-bit pixel representing the blurred result.
// Kernel: 1 2 1
//         2 4 2
//         1 2 1
// Blurred pixel = (sum of weighted input pixels) / 16
module gaussian_blur (
    input [7:0] pixel_00, input [7:0] pixel_01, input [7:0] pixel_02,
    input [7:0] pixel_10, input [7:0] pixel_11, input [7:0] pixel_12,
    input [7:0] pixel_20, input [7:0] pixel_21, input [7:0] pixel_22,
    output reg [7:0] blurred_pixel
);
    always @(*) begin
        blurred_pixel = (pixel_00 + pixel_01*2 + pixel_02 +
                         pixel_10*2 + pixel_11*4 + pixel_12*2 +
                         pixel_20 + pixel_21*2 + pixel_22) / 16;
    end
endmodule

